import argparse
import sys
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError, TopicAlreadyExistsError, UnknownTopicOrPartitionError
import json

def create_admin_client(bootstrap_servers):
    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=bootstrap_servers,
            api_version=(2, 5, 0),
            security_protocol='PLAINTEXT'
        )
        return admin_client
    except Exception as e:
        print(f"Failed to create admin client: {e}")
        sys.exit(1)

def create_topics(admin_client, topics_config):
    try:
        new_topics = []
        for topic_config in topics_config:
            topic_name = topic_config['name']
            num_partitions = topic_config.get('partitions', 1)
            replication_factor = topic_config.get('replication_factor', 1)
            config = topic_config.get('config', {})
            
            new_topic = NewTopic(
                name=topic_name,
                num_partitions=num_partitions,
                replication_factor=replication_factor,
                topic_configs=config
            )
            new_topics.append(new_topic)
        
        create_result = admin_client.create_topics(new_topics, validate_only=False)
        for topic_name, exception in create_result.items():
            if exception:
                print(f"Failed to create topic {topic_name}: {exception}")
            else:
                print(f"Successfully created topic {topic_name}")
                
    except Exception as e:
        print(f"Error creating topics: {e}")

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Topics:")
        for topic in topics:
            print(f"  {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_configs = admin_client.describe_configs([
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
        ])
        print(f"Configuration for topic {topic_name}:")
        for resource, config in topic_configs.items():
            for key, value in config.items():
                print(f"  {key}: {value}")
    except Exception as e:
        print(f"Error describing topic {topic_name}: {e}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics([topic_name])
        print(f"Successfully deleted topic {topic_name}")
    except Exception as e:
        print(f"Error deleting topic {topic_name}: {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers')
    parser.add_argument('--action', required=True, choices=['create', 'list', 'describe', 'delete'], help='Action to perform')
    parser.add_argument('--topics', help='JSON string with topic configurations')
    parser.add_argument('--topic-name', help='Name of topic for describe/delete actions')
    
    args = parser.parse_args()
    
    admin_client = create_admin_client(args.bootstrap_servers)
    
    if args.action == 'create':
        if not args.topics:
            print("Error: --topics argument required for create action")
            sys.exit(1)
        
        try:
            topics_config = json.loads(args.topics)
        except json.JSONDecodeError:
            print("Error: Invalid JSON in --topics argument")
            sys.exit(1)
            
        create_topics(admin_client, topics_config)
        
    elif args.action == 'list':
        list_topics(admin_client)
        
    elif args.action == 'describe':
        if not args.topic_name:
            print("Error: --topic-name argument required for describe action")
            sys.exit(1)
        describe_topic(admin_client, args.topic_name)
        
    elif args.action == 'delete':
        if not args.topic_name:
            print("Error: --topic-name argument required for delete action")
            sys.exit(1)
        delete_topic(admin_client, args.topic_name)

if __name__ == '__main__':
    main()